import { Button as ChakraButton, ButtonProps as ChakraButtonProps } from '@chakra-ui/react';
import { forwardRef, ReactNode } from 'react';

export type ButtonVariant =
  | 'colorPicker'
  | 'donationAmount'
  | 'icon'
  | 'link'
  | 'menuItem'
  | 'nav'
