  | 'tertiaryWhite'
  | 'text'
  | 'toggle'
  | 'danger'
  | 'submit'
  | 'defaultSubmit'
  | 'unstyled';

export type SizeVariant = 'sm' | 'md' | 'lg';

export type ButtonProps = Overwrite<
  ChakraButtonProps,
  {
    children?: ReactNode;
    isDestructive?: boolean;
    size?: SizeVariant;
    variant?: ButtonVariant;
  }
>;

// forwardRef is required for Popovers on Buttons
export const Button = forwardRef<HTMLButtonElement, ButtonProps>((props, ref) => {
  const {
    children,
    form,
    iconSpacing = 1,
    size = 'md',
    type,
    variant = 'primary',
    ...rest
  } = props;

  const buttonType = type || (form ? 'submit' : 'button');

  return (
    <ChakraButton
      form={form}
      iconSpacing={iconSpacing}
      ref={ref}
      size={size}
      type={buttonType}
      variant={variant}
      {...rest}
    >
      {children}
    </ChakraButton>
  );
});

